metadata_processor_prompt.output_format:
Return a valid JSON object with NO trailing commas:
```json
{
    "analysis": {
        "detected_patterns": ["PATTERN_ID_1", "PATTERN_ID_2"],
        "genre": "romcom|drama|fantasy|comedy|mystery",
        "core_hook": "One-sentence description of the title's main appeal",
        "tone": "playful|serious|absurd|dramatic|mysterious"
    },
    "title_en": "Primary Localized English Title",
    "title_en_alt": "Alternative title option",
    "author_en": "Surname GivenName (Hepburn Romaji)",
    "illustrator_en": "Surname GivenName or Pen Name",
    "publisher_en": "Publisher Name (Romanized/Translated)",
    "series_en": "Series name if applicable, null otherwise",
    "chapters": [
        {
            "id": "chapter_id_from_manifest",
            "title_jp": "Original Japanese title",
            "title_en": "Localized English chapter title",
            "emotional_proximity_signals": {
                "CharacterName": {
                    "eps_score": -0.35,
                    "voice_band": "COOL",
                    "signals": {
                        "keigo_shift": -0.2,
                        "sentence_length_delta": -0.1,
                        "particle_signature": -0.05,
                        "pronoun_shift": 0,
                        "dialogue_volume": 0,
                        "direct_address": 0
                    }
                }
            },
            "scene_intents": ["ESTABLISH_VOICE", "TENSION_BUILD", "EMOTIONAL_PEAK", ...]
        }
    ],
    // REQUIRED - Every character with dialogue MUST have an entry here
    "character_voice_fingerprints": [
        {
            "canonical_name_en": "Tanaka (or character's EN name)",
            "archetype": "tsundere",
            "contraction_rate": 0.65,
            "sentence_length_bias": "medium",
            "forbidden_vocabulary": ["love", "I need you", "genuinely care"],
            "preferred_vocabulary": ["whatever", "not like I", "as if"],
            "signature_phrases": ["It's not like I like you or anything!", "Hmph!", "Whatever!"],
            "verbal_tics": ["—ne?", "I mean,", "well..."],
            "emotional_patterns": {
                "deflection-anger": ["crosses arms", "looks away", ' "Whatever"'],
                "flustered-denial": ["stammers", "face turns red", "trips over words"],
                "rare-softness": ["voice drops", "eye contact", "genuine smile"]
            },
            "dialogue_samples": [
                {"jp": "あんたが困ろうが知ったこっちゃない!", "en": "I don't care if you're troubled!"},
                {"jp": "べつに…あんたのためじゃないんだから!", "en": "It's not like... I'm doing this for YOU or anything!"}
            ]
        }
    ],
    "signature_phrases": [
        {
            "character_en": "Tanaka",
            "phrase_jp": "べつに",
            "phrase_en": "It's not like...",
            "frequency": "very_high",
            "context": "tsundere deflection pattern",
            "translation_notes": "Must preserve ellipsis for comedic timing"
        },
        {
            "character_en": "Sato",
            "phrase_jp": "うふん♪",
            "phrase_en": "Ufun♪",
            "frequency": "medium",
            "context": "genki glee",
            "translation_notes": "Onomatopoeia signature; keep katakana style"
        }
    ],
    "scene_intent_map": [
        {
            "chapter_id": "chapter_01",
            "scenes": [
                {
                    "scene_id": "chapter_01_01",
                    "location": "school_entrance",
                    "primary_intent": "ESTABLISH_VOICE",
                    "secondary_intents": ["WORLD_BUILDING"],
                    "emotional_goal": "Reader meets protagonist's voice; tonal anchor",
                    "key_moments": ["First-person internal monologue", "School atmosphere description"]
                },
                {
                    "scene_id": "chapter_01_02",
                    "location": "classroom",
                    "primary_intent": "ESTABLISH_VOICE",
                    "secondary_intents": ["RELATIONSHIP_SHIFT"],
                    "emotional_goal": "Introduce rival character with contrasting voice",
                    "key_moments": ["Tanaka's cold greeting", "Protagonist's internal reaction"]
                }
            ]
        }
    ],
    "localization_notes": {
        "honorifics_mode": "KEEP JP|DROP JP",
        "name_order": "JP|WESTERN",
        "register_shifts": [
            {
                "character": "Tanaka",
                "scenario": "speaking_to_protagonist",
                "keigo_level": "plain|contemptuary|casual| polite|respectful",
                "notes": "Uses plain when angry, polite when forced to be social"
            }
        ]
    }
}
```
